const serviceItems = $('Service List').all();
const resultItems = items;
const results = [];
let allOk = true;

function readStatusCode(result) {
  const rawStatus = result.statusCode ?? result.status ?? result.response?.statusCode;
  const numericStatus = Number(rawStatus);
  return Number.isFinite(numericStatus) ? numericStatus : null;
}

for (let i = 0; i < serviceItems.length; i++) {
  const service = serviceItems[i].json;
  const result = resultItems[i]?.json || {};
  const statusCode = readStatusCode(result);
  const errorMessage = result.error?.message || result.error || result.message || null;
  const okStatuses = Array.isArray(service.okStatuses) ? service.okStatuses : [200, 204, 301, 302, 303, 307, 308];
  const isOnline = statusCode !== null && okStatuses.includes(statusCode) && !errorMessage;
  const isDown = !isOnline;

  if (isDown) allOk = false;

  results.push({
    name: service.name,
    url: service.url,
    status: isDown ? "DOWN" : "ONLINE",
    statusCode,
    error: isDown ? (errorMessage || `HTTP ${statusCode ?? 'Failed'}`) : null
  });
}

return [{
  json: {
    services: results,
    all_ok: allOk
  }
}];

const stdout = items[0].json.stdout || "";
const lines = stdout.split("\n");

const expectedContainers = {
  "automation-01": [
    "netdata",
    "portainer",
    "uptime-kuma",
    "homepage",
    "watchtower",
    "nginx-proxy-manager",
    "n8n",
    "life-control-center",
    "semaphore"
  ],
  "docker-01": [
    "netdata",
    "portainer_agent",
    "dozzle",
    "watchtower",
    "cloudflared",
    "nextcloud-app",
    "nextcloud-redis",
    "nextcloud-db"
  ],
  "colmado-db": [
    "supabase-db",
    "supabase-storage",
    "supabase-meta",
    "supabase-studio",
    "supabase-pooler",
    "realtime-dev.supabase-realtime",
    "supabase-auth",
    "supabase-edge-functions",
    "supabase-kong",
    "supabase-rest",
    "supabase-analytics",
    "supabase-vector",
    "supabase-imgproxy"
  ]
};

const running = {
  "automation-01": {},
  "docker-01": {},
  "colmado-db": {}
};

const hostOffline = {
  "automation-01": false,
  "docker-01": false,
  "colmado-db": false
};

const diskUsage = {
  "automation-01": null,
  "docker-01": null,
  "colmado-db": null
};

let parsingSection = "";
let currentDiskHost = "";

for (const rawLine of lines) {
  const line = rawLine.trim();
  if (!line) continue;

  if (line.includes("=== DOCKER STATUS ===")) {
    parsingSection = "DOCKER";
    continue;
  }
  if (line.includes("=== DISK USAGE ===")) {
    parsingSection = "DISK";
    continue;
  }

  if (parsingSection === "DOCKER") {
    const parts = line.split("|");
    if (parts.length >= 2) {
      const host = parts[0].trim();
      const containerName = parts[1].trim();
      if (containerName === "OFFLINE") {
        hostOffline[host] = true;
      } else if (parts.length >= 3) {
        const status = parts[2].trim();
        running[host][containerName] = status;
      }
    }
  } else if (parsingSection === "DISK") {
    if (line.startsWith("=== ") && line.endsWith(" ===")) {
      currentDiskHost = line.replace(/===/g, "").trim();
      continue;
    }

    if (currentDiskHost) {
      if (line === "OFFLINE") {
        diskUsage[currentDiskHost] = "OFFLINE";
      } else {
        const parts = line.split(/\s+/);
        if (parts.length >= 6 && parts[5] === "/") {
          diskUsage[currentDiskHost] = {
            size: parts[1],
            used: parts[2],
            available: parts[3],
            usage: parts[4]
          };
        }
      }
    }
  }
}

const containersSummary = {};
let allContainersOk = true;

for (const host of ["automation-01", "docker-01", "colmado-db"]) {
  if (hostOffline[host]) {
    containersSummary[host] = { status: "OFFLINE", all_ok: false };
    allContainersOk = false;
    continue;
  }

  const expected = expectedContainers[host];
  const active = running[host];
  const details = [];
  let hostOk = true;

  for (const name of expected) {
    if (active[name]) {
      details.push({ name, status: "RUNNING", details: active[name] });
    } else {
      details.push({ name, status: "MISSING" });
      hostOk = false;
      allContainersOk = false;
    }
  }

  containersSummary[host] = {
    status: hostOk ? "ALL_OK" : "MISSING_CONTAINERS",
    all_ok: hostOk,
    details
  };
}

return [{  json: {
    containers: containersSummary,
    all_containers_ok: allContainersOk,
    disk_usage: diskUsage
  }
}];

const stdout = items[0].json.stdout || "";
const data = {};
for (const line of stdout.split("\n")) {
  const index = line.indexOf("=");
  if (index === -1) continue;
  const key = line.slice(0, index).trim();
  const value = line.slice(index + 1).trim();
  data[key] = value;
}

const hasDataBackup = Boolean(data.DATA_BACKUP);
const hasDbBackup = Boolean(data.DB_BACKUP);
const hasHtmlBackup = Boolean(data.HTML_BACKUP);
const successLog = Number(data.SUCCESS_LOG || 0) > 0;

const allGood = hasDataBackup && hasDbBackup && hasHtmlBackup && successLog;

return [{
  json: {
    host: data.HOST || "docker-01",
    date: data.DATE,
    backup_ok: allGood,
    details: {
      data: { file: data.DATA_BACKUP, size: data.DATA_SIZE },
      db: { file: data.DB_BACKUP, size: data.DB_SIZE },
      html: { file: data.HTML_BACKUP, size: data.HTML_SIZE },
      success_message_found: successLog
    }
  }
}];

const stdout = items[0].json.stdout || "";
const data = {};
for (const line of stdout.split("\n")) {
  const index = line.indexOf("=");
  if (index === -1) continue;
  const key = line.slice(0, index).trim();
  const value = line.slice(index + 1).trim();
  data[key] = value;
}

const usbMounted = Number(data.USB_MOUNT || 0) > 0;
const hasLatestBackup = Boolean(data.LATEST_BACKUP);
const backupsLast24h = Number(data.BACKUP_COUNT_24H || 0);

const backupOk = usbMounted && hasLatestBackup && backupsLast24h > 0;

return [{
  json: {
    host: data.HOST || "proxmox",
    date: data.DATE,
    usb_mounted: usbMounted,
    backup_ok: backupOk,
    backups_last_24h: backupsLast24h,
    total_backups: Number(data.TOTAL_BACKUPS || 0),
    latest_backup: data.LATEST_BACKUP,
    latest_backup_time: data.LATEST_BACKUP_TIME,
    usb_usage: data.USB_DISK
  }
}];

const services = $('Aggregate Health Check').item.json;
const hosts = $('Aggregate Host Checks').item.json;
const nextcloudBackup = $('Aggregate Nextcloud Backup').item.json;
const proxmoxBackup = $('Aggregate Proxmox Backup').item.json;

const warningThreshold = 80;
const criticalThreshold = 90;
const now = new Date().toLocaleString("en-US", {
  timeZone: "America/Santo_Domingo",
  dateStyle: "medium",
  timeStyle: "short"
});

let highestStatus = "Healthy";
let embedColor = 3066993;

function setCritical() {
  highestStatus = "Critical";
  embedColor = 15158332;
}

function setWarning() {
  if (highestStatus !== "Critical") {
    highestStatus = "Warning";
    embedColor = 16776960;
  }
}

const downServices = services.services.filter((s) => s.status === "DOWN");
if (downServices.length > 0) setCritical();

const missingContainers = [];
for (const [host, info] of Object.entries(hosts.containers)) {
  if (info.status === "OFFLINE") {
    missingContainers.push(`${host} offline`);
    setCritical();
  } else if (!info.all_ok) {
    const missing = info.details.filter((d) => d.status === "MISSING").map((d) => d.name);
    if (missing.length > 0) {
      missingContainers.push(`${host}: ${missing.join(", ")}`);
      setCritical();
    }
  }
}

const diskLines = [];
const diskWarnings = [];
for (const [host, disk] of Object.entries(hosts.disk_usage)) {
  if (disk === "OFFLINE") {
    diskLines.push(`FAIL ${host}: offline`);
    diskWarnings.push(`${host} disk check offline`);
    setCritical();
    continue;
  }

  if (disk && disk.usage) {
    const usageVal = parseInt(String(disk.usage).replace("%", ""), 10);
    const prefix = usageVal >= criticalThreshold ? "FAIL" : usageVal >= warningThreshold ? "WARN" : "OK";
    diskLines.push(`${prefix} ${host}: ${disk.usage} used, ${disk.available} free`);

    if (usageVal >= criticalThreshold) {
      diskWarnings.push(`${host} critically full: ${disk.usage} (${disk.used} / ${disk.size})`);
      setCritical();
    } else if (usageVal >= warningThreshold) {
      diskWarnings.push(`${host} nearly full: ${disk.usage} (${disk.used} / ${disk.size})`);
      setWarning();
    }
  } else {
    diskLines.push(`FAIL ${host}: unknown`);
    diskWarnings.push(`${host} disk status unknown`);
    setCritical();
  }
}

const backupLines = [];
if (nextcloudBackup.backup_ok) {
  backupLines.push(`OK Nextcloud: DB ${nextcloudBackup.details.db.size}, Data ${nextcloudBackup.details.data.size}, HTML ${nextcloudBackup.details.html.size}`);
} else {
  backupLines.push("FAIL Nextcloud: backup missing or incomplete");
  setCritical();
}

if (proxmoxBackup.usb_mounted) {
  if (proxmoxBackup.backup_ok) {
    backupLines.push(`OK Proxmox: ${proxmoxBackup.backups_last_24h} backups in 24h, ${proxmoxBackup.total_backups} total`);
  } else {
    backupLines.push("FAIL Proxmox: USB mounted but no backup found in last 24h");
    setCritical();
  }
} else {
  backupLines.push(`WARN Proxmox: USB backup drive not mounted; usage snapshot ${proxmoxBackup.usb_usage || 'unavailable'}`);
  setWarning();
}

const serviceField = downServices.length === 0
  ? `OK ${services.services.length}/${services.services.length} monitored web checks responded as expected.`
  : downServices.map((s) => `FAIL ${s.name}: ${s.error || 'No response'}`).join("\n");

const containerField = missingContainers.length === 0
  ? "OK All expected containers are running on automation-01, docker-01, and colmado-db."
  : missingContainers.map((line) => `FAIL ${line}`).join("\n");

const summaryParts = [
  `${services.services.length - downServices.length}/${services.services.length} web checks OK`,
  missingContainers.length === 0 ? "containers OK" : `${missingContainers.length} container issue(s)`,
  diskWarnings.length === 0 ? "disk OK" : `${diskWarnings.length} disk warning(s)`,
  nextcloudBackup.backup_ok ? "Nextcloud backup OK" : "Nextcloud backup failed",
  proxmoxBackup.backup_ok ? "Proxmox backup OK" : "Proxmox backup attention"
];

const title = highestStatus === "Healthy"
  ? "YZEE Labs Daily Health: All Systems Nominal"
  : highestStatus === "Warning"
    ? "YZEE Labs Daily Health: Warning"
    : "YZEE Labs Daily Health: Attention Required";

return [{
  json: {
    username: "Homelab Reporter",
    embeds: [{
      title,
      description: `Run time: **${now}**\n${summaryParts.join(" | ")}`,
      color: embedColor,
      fields: [
        { name: "Web Services", value: serviceField.slice(0, 1024), inline: false },
        { name: "Docker Containers", value: containerField.slice(0, 1024), inline: false },
        { name: "Disk Usage", value: diskLines.join("\n").slice(0, 1024), inline: false },
        { name: "Backups", value: backupLines.join("\n").slice(0, 1024), inline: false }
      ],
      footer: {
        text: "YZEE Labs Control Plane | n8n Automation Engine"
      },
      timestamp: new Date().toISOString()
    }]
  }
}];
